import java.sql.*;

public class SQLInjectionFixedExample {

    public static void main(String[] args) {
        try {
            // Simulating user input (which should not be done this way in production code)
            String userInput = "admin' OR '1'='1";

            // Connecting to a SQLite database (you can replace this with any SQL database)
            Connection connection = DriverManager.getConnection("jdbc:sqlite:sample.db");

            // Fixed query construction using parameterized queries
            String query = "SELECT * FROM users WHERE username = ?";

            PreparedStatement preparedStatement = connection.prepareStatement(query);
            preparedStatement.setString(1, userInput);

            ResultSet resultSet = preparedStatement.executeQuery();

            while(resultSet.next()) {
                System.out.println("User found: " + resultSet.getString("username"));
            }

            connection.close();
        } catch (SQLException e) {
            System.err.println("SQL Exception: " + e.getMessage());
        }
    }
}

